	weapon_frames:{dagger:16, sword:[17,21], axe:[17,15], mace:[17,15], thrown:[17,16], staff:15, polearm:15, scepter:17, wand:17, javelin:16, spear:22, bow:16, crossbow:19, orb:17},
	fcr_frames:13, fcr_bp:[0, 9, 20, 37, 63, 105, 200],
